import axios from "axios";
import showMessage from "@/utils/showMessage.js";

const ins = axios.create(); // 创建一个axios的实例
ins.interceptors.response.use(function(resp) {
  if (resp.data.code !== 0) {
    showMessage({
      content: resp.data.msg,
      type: "info",
      duration: 1500,
    });
    return null;
  }
  return resp.data.data;
});

export default ins;
